import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"载具基础驾驶指南","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/器用类/载具基础驾驶指南.md","filePath":"4.资源分区/6.技艺及称号/器用类/载具基础驾驶指南.md"}'),d={name:"4.资源分区/6.技艺及称号/器用类/载具基础驾驶指南.md"};function _(p,a,l,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"载具基础驾驶指南",tabindex:"-1"},[s("载具基础驾驶指南 "),e("a",{class:"header-anchor",href:"#载具基础驾驶指南","aria-label":'Permalink to "载具基础驾驶指南"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"灵魂蓝调014")])])],-1),o('<h1 id="载具基础驾驶指南-1" tabindex="-1">载具基础驾驶指南 <a class="header-anchor" href="#载具基础驾驶指南-1" aria-label="Permalink to &quot;载具基础驾驶指南&quot;">​</a></h1><p>各种看了说明书就开机体的主角们（例如阿姆罗）看的说明书就是这本书，如果你信的话（）</p><p>载具格斗技术<br> D+500<br> 特殊的，这是一种不提供属性的技艺<br> 格斗武装：若你在驾驶D级及以上的，拥有至少两个肢体的载具（一般为战斗机器人，但部分有类似机械臂机构的重型载具同样适用，例如格兰蒂斯坦克）你懂得如何运用载具的肢体进行近身战斗，此时你视为在使用武器伤害3L 提供1附加成功 造成严重伤害 伤害类型为钝击 的类肉搏武器武装，能按照肉搏武器规则产生冲击点数<br> 战斗技术：在使用任意载具武装时，你可以将驾驶检定主属性一半（向下取整）的威猛转化为高速或破甲（在发起攻击时自由分配）<br> 特殊的，若你使用其他载具武装进行攻击，你仍能适用战斗技术的效果，但没有格斗武装的好处</p><p>虚假锁定战术<br> D+500<br> 假装锁定某个目标，然后做出攻击的趋势，但很快就转移了目标或者停顿了数秒才继续攻击，这个战术也可以简称为，快慢刀<br> 你可以使用一个移动动作做出虚假的攻击意图，此时你令一名目标使用感知+洞察+察言观色+武学掌握或弹道学（由对方选择）与你的驾驶检定对抗，若你获胜，则本轮内的下一次载具武装攻击视为具有D级措手不及，若你如此经历了一场影片，随着对战术的掌握，提升为C级措手不及，若对方并未收到措手不及的影响，则改为让此次攻击具有器用技能*1的高速</p><p>坚实防御战术<br> D+1000<br> 若你在驾驶D级及以上的，拥有至少两个肢体的载具（一般为战斗机器人，但部分有类似机械臂机构的重型载具同样适用，例如格兰蒂斯坦克）你懂得如何运用载具的肢体进行保护脆弱部位。你可以使用一个移动动作让载具摆出格挡的姿态。直到你的下回合开始，你的载具额外获得等同于器用等级*1的格挡防御</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
